"""
MKT Original Commentary — Genesis chapters 36–37
Run: python3 scripts/zc-original-genesis-36-37.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- Ch 36 (Edomite genealogy): entries focus on structural/formula markers,
  the key term ʾallûp (chieftain), the Horite/Edomite distinction, the
  significance of Amalek's origin (v.12), the king-list anachronism (v.31),
  and the unique hapax in v.24. The name discrepancy between Esau's wives
  here vs. 26:34-35 and 28:9 is noted at vv.2-3 as a textual feature
  without resolving the source-critical debate.
- Ch 37 (Joseph sold): the ketonet passim (v.3) is treated as "long-sleeved
  robe of royal style" following the 2 Sam 13:18-19 parallel, not KJV
  "coat of many colors." The Ishmaelite/Midianite/Medanite terminological
  variation (vv.25-28, 36) is noted as reflecting fluid tribal identity
  in the narrative tradition, not an error requiring harmonization.
- Joseph's ḥinnēnî (v.13) is connected to the patriarchal availability
  formula (22:1; Abraham); this is a key typological marker that mkt-original
  notes but does not develop (that's mkt-christ's domain).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "36": {
    "1": '<p><strong>אֵלֶּה תֹּלְדוֹת עֵשָׂו הוּא אֱדוֹם</strong> (<em>ʾēlleh tōlĕḏôt ʿēśāw hûʾ ʾĔḏôm</em>) — "these are the generations of Esau, that is, Edom." The <em>tôlĕḏôt</em> formula appears again at v. 9 — the only chapter in Genesis with a double toledoth introduction. The parenthetical <em>hûʾ ʾĔḏôm</em> (he is Edom) is the first use of the identification-gloss within a toledoth formula itself; the chapter begins by establishing the national identity that will persist: Esau = Edom. The same double-gloss structure (person = nation) recurs throughout the chapter, anchoring the genealogy in geopolitical reality.</p>',
    "2": '<p><strong>מִבְּנוֹת כְּנָעַן</strong> (<em>mibbĕnôt kĕnaʿan</em>, from the women of Canaan) — Esau\'s three wives are introduced; their names here differ from the earlier accounts (26:34-35 gives Judith bat Beeri and Basemath bat Elon; 28:9 gives Mahalath bat Ishmael). The textual tradition preserves two name-sets for Esau\'s wives — the variation likely reflects different genealogical sources assembled in the Edomite record. The names <em>ʿĂḏāh</em> (Adah — "ornament"), <em>ʾŌhŏlîḇāmāh</em> (Oholibamah — "tent of the high place"), and <em>Bāśĕmat</em> (Basemath — "fragrant") carry their own semantic weight but the text does not develop it. The ethnic identifications — <em>haḥittî</em> (Hittite), <em>haḥiwwî</em> (Hivite) — mark all three as Canaanite women outside the covenant line, which explains the earlier parental grief (26:35).</p>',
    "3": '<p><strong>בַּת-יִשְׁמָעֵאל</strong> (<em>bat-yišmāʿēʾl</em>, daughter of Ishmael) — Basemath is identified as Ishmael\'s daughter; in 28:9 this wife is named Mahalath. The Ishmael-connection places Esau in relationship with the other excluded son of Abraham — two excluded sons joined by marriage. The sister of Nebaioth — Nebaioth is Ishmael\'s firstborn (25:13) — anchors the genealogical connection. The narrative does not comment on the marriage to Ishmael\'s daughter; it is simply registered as a third Edomite wife alongside the Canaanite two.</p>',
    "4": '<p><strong>אֶת-אֱלִיפַז</strong> (<em>ʾet-ʾĔlîpaz</em>) and <strong>רְעוּאֵל</strong> (<em>Rĕʿûʾēl</em>) — Eliphaz (from Adah) and Reuel (from Basemath) are named; Eliphaz will produce the Teman clan (v. 11) and will become famous as the name of Job\'s first friend (Job 2:11), associated with "the Temanite." Reuel (meaning "friend of God" or "associate of El") is a significant name in biblical tradition — it reappears as the name of Moses\' father-in-law in Exod 2:18 and Num 10:29 (though usually given as Jethro). The Edomite ancestry of the name Reuel is not developed in the Moses context but forms part of the larger Midianite-Edomite-Ishmaelite tribal network of the Transjordan.</p>',
    "5": '<p><strong>יְעוּשׁ וְיַעְלָם וְקֹרַח</strong> (<em>yĕʿûš wĕyaʿlām wĕqōraḥ</em>) — Jeush, Jalam, and Korah born to Oholibamah. Korah is an important name: it appears again as the name of the Levitical rebel of Num 16 (a different individual, but the name\'s occurrence in both Edomite and Levitical contexts is notable). <strong>בְּאֶרֶץ כְּנָעַן</strong> (in the land of Canaan) — the geographical note closes the family introduction; Esau\'s children were all born in Canaan before the territorial separation of v. 6-8.</p>',
    "6": '<p><strong>וַיֵּלֶךְ אֶל-אֶרֶץ מִפְּנֵי יַעֲקֹב אָחִיו</strong> (<em>wayyēleḵ ʾel-ʾereṣ mippĕnê yaʿăqōḇ ʾāḥîw</em>) — "he went to a land from before Jacob his brother." <em>Mippĕnê</em> (from before, away from the presence of) — the same idiom appears in Cain\'s departure "from before YHWH" (4:16); here it is voluntary separation from a brother rather than a curse-driven exile. The departure catalogue is comprehensive: wives, sons, daughters, household members, livestock, goods — everything Esau acquired in Canaan goes with him. The verb <em>lāqaḥ</em> (took/took along) used for all his possessions echoes the same verb used in the Laban conflict (31:1) — Esau departs legitimately with his own property.</p>',
    "7": '<p><strong>כִּי-הָיָה רְכוּשָׁם רָב מִשֶּׁבֶת יַחְדָּו</strong> (<em>kî-hāyāh rĕḵûšām rāḇ miššeḇet yaḥdāw</em>) — "for their possessions had become too great for them to dwell together." The same explanation was given for the Abraham-Lot separation (13:6: "the land could not support them both because of their livestock"). The narrative template is repeated: covenant heir separates from non-heir because the land cannot hold both. <em>Rĕḵûš</em> (possessions, property — the word used for Abraham\'s wealth in 12:5; 13:6; and Lot\'s wealth in 13:6); <em>miqneh</em> (livestock, property in animals) follows as the specific category that made joint habitation impossible.</p>',
    "8": '<p><strong>וַיֵּשֶׁב עֵשָׂו בְּהַר שֵׂעִיר</strong> (<em>wayyēšeḇ ʿēśāw bĕhar śēʿîr</em>) — "Esau settled in the hill country of Seir." The verb <em>yāšaḇ</em> (to dwell, settle) — Esau settles; Jacob will also "settle" (37:1, the parallel phrase that opens the Joseph narrative). The territory name <em>śēʿîr</em> (Seir) is thematically linked to <em>śāʿîr</em> (hairy) — Esau was hairy (25:25); the man and his mountain share their root. The mountain territory of Seir in Transjordan (south of the Dead Sea) becomes the permanent Edomite homeland; the identification <em>hûʾ ʾĔḏôm</em> (he is Edom) follows Esau\'s name one more time to anchor the equation.</p>',
    "9": '<p><strong>וְאֵלֶּה תֹּלְדוֹת עֵשָׂו אֲבִי אֱדוֹם בְּהַר שֵׂעִיר</strong> — the second <em>tôlĕḏôt</em> formula of ch. 36, introducing the Edomite genealogy as a nation rather than a family. The phrase <em>ʾăḇî ʾĔḏôm</em> (father of Edom) — Esau is the eponymous ancestor: the nation named from the man. <em>Bĕhar śēʿîr</em> (in the hill country of Seir) — the geographical qualifier distinguishes this from the Canaan-born family of vv. 1-8; this is Esau\'s line as it developed in its own territory. The double toledoth is structurally significant: the first (v. 1) introduces the family; the second (v. 9) introduces the nation. Together they trace the movement from person to people.</p>',
    "10": '<p><strong>אֵלֶּה שְׁמוֹת בְּנֵי-עֵשָׂו</strong> (<em>ʾēlleh šĕmôt bĕnê-ʿēśāw</em>) — "these are the names of Esau\'s sons." The name-list formula (<em>ʾēlleh šĕmôt</em>) is the same used to introduce the Israelites going to Egypt (Exod 1:1). Eliphaz ben Adah and Reuel ben Basemath are the two primary sons; the Oholibamah-sons were listed in v. 5 and will reappear in v. 14. The structure of the name-list covers the three maternal lines that organize the rest of the genealogy.</p>',
    "11": '<p><strong>תֵּימָן וְאוֹמָר צְפוֹ וְגַעְתָּם וּקְנַז</strong> — the five sons of Eliphaz. <em>Têmān</em> (Teman) is the most significant: Teman becomes the name of an Edomite region (Jer 49:7, 20; Obad 1:9; Hab 3:3; Amos 1:12) associated with wisdom (<em>ḥāḵmāh</em>; cf. Jer 49:7: "Is there no longer wisdom in Teman?"). Eliphaz the Temanite (Job 2:11) bears this clan name as his geographic identity. <em>Qĕnaz</em> (Kenaz) — also a clan name; the Kenizzite clan (cf. Gen 15:19; Num 32:12) may be connected to this Edomite Kenaz, and Othniel ben Kenaz (the first judge; Judg 3:9-11) appears to come from a Kenizzite-absorbed-into-Judah background.</p>',
    "12": '<p><strong>וְתִמְנַע הָיְתָה פִילֶגֶשׁ לֶאֱלִיפַז</strong> (<em>wĕtimnaʿ hāyĕtāh pîlegeš lĕʾĔlîpaz</em>) — "Timna was a concubine of Eliphaz." <em>Pîlegeš</em> (concubine — a secondary wife with legal standing but lower status than a primary wife; the word is of uncertain etymology; it appears from the beginning of the patriarchal narratives for Hagar, Bilhah, Zilpah). <strong>וַתֵּלֶד לֶאֱלִיפַז אֶת-עֲמָלֵק</strong> (she bore Amalek to Eliphaz) — the birth notice of Amalek; <em>ʿămālēq</em> becomes the name of Israel\'s paradigmatic enemy: the nation that attacked Israel from behind at Rephidim (Exod 17:8-16), was condemned to permanent war with YHWH (Exod 17:16), and whose destruction was demanded by Samuel (1 Sam 15:2-3). Amalek is a grandson of Esau through a concubine — outside the direct heir-line even within Edom. The brief parenthetical notice in the genealogy is the origin-story of Israel\'s longest-running military enemy.</p>',
    "13": '<p><strong>נַחַת וָזֶרַח שַׁמָּה וּמִזָּה</strong> — the four sons of Reuel: Nahath, Zerah, Shammah, Mizzah. Zerah will appear in 38:30 as the name of one of Judah\'s sons by Tamar — a name shared between the Edomite line and the Judahite line (cf. also Zerah son of Simeon, Num 26:13). The name-sharing reflects the kinship networks of the region. <em>Bĕnê ḇāśĕmat</em> (sons of Basemath) — the maternal identification; the genealogy consistently tracks matrilineal descent alongside patrilineal, perhaps because Esau\'s children\'s political standing in Edom depended on both lines of descent.</p>',
    "14": '<p>The sons of Oholibamah are listed again (already appeared in v. 5: Jeush, Jalam, Korah). The repetition with the full identification — <em>bat-ʿănāh bat-ṣiḇʿôn</em> (daughter of Anah, daughter [i.e., granddaughter] of Zibeon) — serves the genealogical record by specifying her Horite ancestry (Anah and Zibeon are Horite chieftains in vv. 20-29). Oholibamah is thus the bridge-figure between the Edomite (Esau\'s line) and Horite (Seir\'s line) genealogies that the chapter interlaces.</p>',
    "15": '<p><strong>אַלּוּפֵי בְנֵי-עֵשָׂו</strong> (<em>ʾallûpê ḇĕnê-ʿēśāw</em>) — "the chiefs of Esau\'s sons." <em>ʾAllûp</em> (chief, tribal leader — from <em>ʾelepp</em>, thousand; the chieftain is the leader of a military/economic thousand-unit; the word appears 12× in this chapter, the highest concentration in the Torah by far). The term is distinct from <em>melek</em> (king): Edom is governed by tribal chieftains before it develops dynastic kingship (vv. 31-39). The chieftain structure reflects a pre-monarchic tribal confederacy. <em>Bĕḵōr ʿēśāw ʾĔlîpaz</em> (Esau\'s firstborn Eliphaz) — the firstborn status of Eliphaz is stated, making Teman (his firstborn son, v. 15) the heir of the heir.</p>',
    "16": '<p><strong>אַלּוּף קֹרַח</strong> (<em>ʾallûp qōraḥ</em>) — Korah appears in this list; he was born to Oholibamah (v. 5, 14) and is now listed among the "chiefs descended from Eliphaz" — either because his mother married into the Eliphaz line or because the text\'s genealogical accounting is complex. <em>ʾAmmêqĕlēq</em> (these are the chiefs of Amalek) — Amalek is counted among the Eliphaz chiefs despite being born of a concubine (v. 12): his lineage is Eliphaz; his maternal line is unnamed Horite/Timna. The social placement of Amalek within Edomite chieftainship establishes that Amalek is an Edomite sub-clan, not a separate nation — the national identity develops later.</p>',
    "17": '<p>The Reuel-chiefs: Nahath, Zerah, Shammah, Mizzah — the same four sons as v. 13 now listed with the <em>ʾallûp</em> title. <em>ʾAllûpê rĕʿûʾēl bĕʾereṣ ʾĔḏôm</em> (chiefs of Reuel in the land of Edom) — "the land of Edom" is now the geographic identifier; the territory is named, settled, and organized. The <em>ḇĕnê ḇāśĕmat ʾēšet ʿēśāw</em> (sons of Bashemath, wife of Esau) closure tracks the maternal line one more time.</p>',
    "18": '<p>The Oholibamah-chiefs: Jeush, Jalam, Korah. The three Oholibamah sons appear as chieftains in their own right, separate from the Eliphaz-line chiefs. The full identification <em>bat-ʿănāh</em> (daughter of Anah) again specifies the Horite mother, connecting Oholibamah\'s sons to both the Edomite and Horite chieftain traditions. The three-part listing (Eliphaz-chiefs, Reuel-chiefs, Oholibamah-chiefs) maps exactly onto the three wives introduced in vv. 2-3.</p>',
    "19": '<p><strong>אֵלֶּה בְנֵי-עֵשָׂו וְאֵלֶּה אַלּוּפֵיהֶם הוּא אֱדוֹם</strong> — the summary closure of the Esau-chief section: "these are the sons of Esau and these are their chiefs, that is, Edom." The parenthetical identification <em>hûʾ ʾĔḏôm</em> appears for the third time in the chapter (vv. 1, 8, 19) — the narrator is insistent on the Esau = Edom equation. The repetition is not careless; it is the chapter\'s structural refrain, establishing that the nation Edom that Israel will encounter in its history descends directly from Esau, Jacob\'s brother.</p>',
    "20": '<p><strong>אֵלֶּה בְנֵי-שֵׂעִיר הַחֹרִי</strong> (<em>ʾēlleh ḇĕnê-śēʿîr haḥōrî</em>) — "these are the sons of Seir the Horite." The Horite genealogy now appears interleaved with the Edomite. <em>Ḥōrî</em> (Horite) — the pre-Edomite inhabitants of Seir; possibly connected to the Hurrians of northern Mesopotamia (a theory based on partial phonological overlap) or to a local cave-dwelling population (<em>ḥôr</em> = cave in Hebrew). The Edomites displaced the Horites from their territory (Deut 2:12, 22 explicitly states: "just as Israel did to the land it came to possess"). The Horite genealogy in vv. 20-30 is included here because Esau\'s wife Oholibamah is a Horite (daughter of Anah son of Zibeon, vv. 2, 14, 20, 24), making the Horite-Edomite genealogical overlap relevant to the Esau family record. <em>Yōšĕḇê hāʾāreṣ</em> (inhabitants of the land) — the Horites are the indigenous population; their record is preserved within the Edomite genealogy that documents their displacement.</p>',
    "21": '<p><strong>דִּישׁוֹן וְאֵצֶר וְדִישָׁן</strong> — Dishon, Ezer, and Dishan; seven sons of Seir are named in v. 20-21. <em>ʾElleh ʾallûpê haḥōrî bĕnê śēʿîr bĕʾereṣ ʾĔḏôm</em> (these are the Horite chiefs, sons of Seir, in the land of Edom) — the Horite chiefs used the same <em>ʾallûp</em> title as the Edomite chiefs; the political-organizational vocabulary is shared between the two groups. The inclusion of <em>bĕʾereṣ ʾĔḏôm</em> (in the land of Edom) after naming the Horite chiefs indicates that the narrator writes from a perspective after the Edomite takeover: the Horite chiefs governed what is now Edom.</p>',
    "22": '<p><strong>וַתִּמְנַע הָיְתָה אֲחוֹת לוֹטָן</strong> (<em>wĕtimnaʿ hāyĕtāh ʾăḥôt lôṭān</em>) — "Timna was the sister of Lotan." The same Timna who became Eliphaz\'s concubine (v. 12) and bore Amalek is here identified as Lotan\'s sister — Lotan is a Horite son of Seir. This makes Timna a Horite woman who entered the Edomite line through the concubinage of Eliphaz. The genealogical cross-reference knits the Horite and Edomite lineages together through the Amalek-origin story. The sons of Lotan: Hori and Homam (Homam appears as Heman in 1 Chr 1:39 — a textual variant).</p>',
    "23": '<p>The sons of Shobal: Alvan, Manahath, Ebal, Shepho, Onam. Shobal\'s descendants include Manahath — a place name that appears in 1 Chr 8:6 as a settlement of Benjaminites who were exiled to it. The name-to-place-name transition (personal name → toponym) is common in the Table of Nations (Gen 10) and genealogies generally: people-groups and their territories share names because the territory is named after (or names) its settlers. <em>Ebal</em> also appears as a mountain name in Deut 11:29 (Mount Ebal) — whether the mountain was named for this Shobalite clan or vice versa is not determinable from the text.</p>',
    "24": '<p><strong>הוּא עֲנָה אֲשֶׁר מָצָא אֶת-הַיֵּמִם בַּמִּדְבָּר</strong> (<em>hûʾ ʿănāh ʾăšer māṣāʾ ʾet-hayyēmim bammidḇār</em>) — "this is the Anah who found the <em>hayyêmim</em> in the wilderness." <em>Hayyêmim</em> — a hapax legomenon; its meaning is disputed: (1) "hot springs" (Onkelos, many moderns) — reading <em>yēm</em> as related to warmth; (2) "mules" (Samaritan Pentateuch, LXX: <em>ἡμίονοι</em>) — reading <em>yāmîm</em> as a plural of a Semitic word for mule/hybrid animal; (3) "waters" or "sea creatures." The parenthetical note is the only non-name narrative detail in the Horite genealogy; that Anah made a significant discovery while tending his father Zibeon\'s donkeys sets him apart from the other Horite sons. The discovery\'s importance for establishing Anah\'s identity (repeated parenthetical: "this is the Anah") suggests it was a known tradition. Anah\'s significance in the genealogy is that his daughter Oholibamah became Esau\'s wife.</p>',
    "25": '<p><strong>וְאֵלֶּה בְנֵי-עֲנָה דִּישׁוֹן וְאָהֳלִיבָמָה בַּת-עֲנָה</strong> — the children of Anah: Dishon and Oholibamah, daughter of Anah. The daughter Oholibamah appears in the Horite genealogy as Anah\'s daughter — the same Oholibamah who is Esau\'s wife (vv. 2, 14, 18). The genealogy has come full circle: the Horite-section reveals that Oholibamah is both Anah\'s daughter and Zibeon\'s granddaughter, tying the family directly into the Horite lineage of Seir. <em>Dîšôn</em> (Dishon) appears as both a son of Anah and an earlier son of Seir (v. 21) — two different individuals with the same name, which is common in tribal genealogies.</p>',
    "26": '<p>Sons of Dishon (son of Anah, distinct from Dishon son of Seir, v. 21): Hemdan, Eshban, Ithran, Keran. The genealogical depth here (Seir → Anah → Dishon → Hemdan etc.) is three generations from the Horite patriarch; the Edomite genealogy by contrast goes two generations from Esau (Esau → Eliphaz → Teman etc.). The Horite record is more detailed, possibly because it was a more established archival tradition absorbed into the Edomite genealogical document.</p>',
    "27": '<p>Sons of Ezer: Bilhan, Zaavan, Akan. <em>Bilhan</em> is a name shared with a Benjaminite in 1 Chr 7:10 — another instance of name-recurrence across tribal genealogies. The sons of Ezer are listed without further comment; the brevity is appropriate for fourth-generation descendants in the genealogical list. The genealogical lists of ch. 36 preserved more Edomite/Horite family names than survive in any other textual source of this period — the chapter is historically valuable as a Transjordanian genealogical record regardless of its narrative-theological function.</p>',
    "28": '<p>Sons of Dishan (note: spelling variant of Dishon, or a different individual per the genealogy): Uz and Aran. <em>ʿÛṣ</em> (Uz) — the land of Uz is where Job lives (Job 1:1); whether Job\'s Uz is connected to this Horite Uz is uncertain, though the Edomite geographic context of both Job and the Horite genealogy makes it possible. The name Uz also appears in the family of Nahor (22:21) and in a Semitic genealogy at 10:23 — it is a widely distributed Semitic place/people name.</p>',
    "29": '<p><strong>אֵלֶּה אַלּוּפֵי הַחֹרִי</strong> (<em>ʾēlleh ʾallûpê haḥōrî</em>) — "these are the Horite chiefs." The seven Horite sons of Seir are now listed as <em>ʾallûpîm</em> (chiefs) by name: Lotan, Shobal, Zibeon, Anah — the same four named in v. 20. The chieftain-list parallels the Edomite chieftain-lists of vv. 15-18; both peoples used the same political structure (<em>ʾallûp</em>-based tribal confederacy) before the Edomite takeover. The parallel structure of the two lists underscores the integration of Horite and Edomite political culture that the Oholibamah marriage represents genealogically.</p>',
    "30": '<p><strong>לְמִשְׁפְּחֹתָם בְּאַרְצָם</strong> (<em>lĕmišpĕḥōtām bĕʾarṣām</em>) — "according to their clans in their land." The closing summary of the Horite chieftain list uses the same formula that will close the Edomite chieftain list (v. 43: <em>bĕʾereṣ ʾăḥuzzāṯām</em>). <em>Mišpāḥāh</em> (clan, kinship unit — the intermediate social unit between the household [<em>bêt-ʾāḇ</em>] and the tribe [<em>šēḇeṭ</em>]) — both Horites and Edomites are organized by clans with territorial assignments. <em>Bĕʾereṣ śēʿîr</em> (in the land of Seir) — "their land" is Seir; it is the Horites\' ancestral land, now being absorbed by the Edomites.</p>',
    "31": '<p><strong>וְאֵלֶּה הַמְּלָכִים אֲשֶׁר מָלְכוּ בְּאֶרֶץ אֱדוֹם לִפְנֵי מְלָךְ-מֶלֶךְ לִבְנֵי יִשְׂרָאֵל</strong> — "these are the kings who reigned in Edom before any king reigned over the sons of Israel." The phrase <em>lipnê mĕlōḵ-melek liḇnê yiśrāʾēl</em> (before any king reigned over Israel) is a forward-looking anachronism: the narrator knows that Israel will eventually have kings (the first Israelite king, Saul, comes in 1 Sam 10); this note is written from a temporal perspective after kingship in Israel began. The observation is often cited as evidence for a late editorial perspective on the patriarchal narratives. The king-list is notable for its non-dynastic character: each king comes from a different city/region, with no father-son succession until v. 39 (where the wife\'s genealogy, not the king\'s father, is given). Edom\'s pre-monarchic kingship is elective or rotational, not hereditary — structurally different from both Israel\'s later monarchy and the ANE norm of dynastic succession.</p>',
    "32": '<p><strong>בֶּלַע בֶּן-בְּעוֹר</strong> (<em>ḇelaʿ ḇen-bĕʿôr</em>) — the first Edomite king: Bela son of Beor. <em>Beor</em> is also the name of Balaam\'s father (Num 22:5) — whether this is the same family is uncertain; the Transjordanian geography overlaps. <em>Dinhāḇāh</em> (Dinhabah) — the first royal city; its location is unknown in modern geography. The king-list\'s inclusion of city names alongside kings suggests it derives from a royal administrative record, possibly Edomite scribal tradition.</p>',
    "33": '<p><strong>וַיָּמָת בֶּלַע</strong> (<em>wayyāmot belaʿ</em>) — "Bela died." The death formula <em>wayyāmot</em> + succession is the structural backbone of the king-list: each king dies and is replaced by a non-dynastic successor. <em>Yōḇāḇ ben-zeraḥ</em> (Jobab son of Zerah) — Jobab is a name also found in the Table of Nations (10:29 — a son of Joktan); Zerah connects to the Reuelite clan (v. 13 — Reuel\'s son Zerah). <em>Mibbōṣrāh</em> (from Bozrah) — Bozrah was Edom\'s major city (Isa 34:6; 63:1; Jer 49:13, 22; Amos 1:12); its importance in the prophetic literature makes this reference notable. The first king came from Dinhabah; the second from Bozrah — the capital has shifted.</p>',
    "34": '<p><strong>חֻשָׁם מֵאֶרֶץ הַתֵּימָנִי</strong> (<em>ḥûšām mēʾereṣ hattêmānî</em>) — "Husham from the land of the Temanites." The Temanites are the clan of Eliphaz\'s son Teman (v. 11); the third king comes from within the Edomite tribal system — specifically from the Teman region, which will become synonymous with Edomite wisdom in the prophets (Jer 49:7). The succession pattern continues: death → non-dynastic successor from a different geographic center.</p>',
    "35": '<p><strong>הָדַד בֶּן-בְּדַד הַמַּכֶּה אֶת-מִדְיָן בִּשְׂדֵה מוֹאָב</strong> — "Hadad son of Bedad, who defeated Midian in the field of Moab." The fourth king is the only one in the list identified by a military achievement: <em>hammakkeh ʾet-miḏyān</em> (who struck/defeated Midian). The victory over Midian in Moabite territory indicates active Edomite military involvement in the Transjordan — the same region where Midian later becomes important for the Exodus narrative (Moses in Midian; Midianite oppression of Israel in Judges). Hadad\'s city is <em>ʿĂwît</em> (Avith) — unknown location. The military identifier gives Hadad more historical texture than any other king in the list.</p>',
    "36": '<p><strong>שַׂמְלָה מִמַּשְׂרֵקָה</strong> (<em>śamlāh mimmāśrēqāh</em>) — Samlah from Masrekah; the fifth king, also without father-identification (unlike Bela ben Beor and Hadad ben Bedad). The absence of patronym for some kings and its presence for others reflects the non-systematic nature of the king-list — it preserves what was known, not a uniform record. <em>Māśrēqāh</em> (Masrekah) — possibly connected to a root meaning "vineyard of choice vines" (<em>śōrēq</em> = choice vine); the toponym reflects the viticulture of the region.</p>',
    "37": '<p><strong>שָׁאוּל מֵרְחֹבוֹת הַנָּהָר</strong> (<em>šāʾûl mêrĕḥōḇôt hannāhār</em>) — "Shaul from Rehoboth on the river." <em>Rĕḥōḇôt</em> (Rehoboth — "broad places, open spaces") — a place-name that appears also in Isaac\'s well-naming sequence (26:22: <em>rĕḥōḇôt</em>) and as Rehoboth-Ir in the Table of Nations (10:11). <em>Hannāhār</em> (the river) — probably the Euphrates (the standard reference for "the river" in the OT when no other river is specified), which would place this Rehoboth in northern Mesopotamia — a surprising origin for an Edomite king. Alternatively, it is a river of the Edomite region. The name Shaul (Saul) is identical to the first Israelite king\'s name — a pre-Israelite precedent for the name.</p>',
    "38": '<p><strong>בַּעַל חָנָן בֶּן-עַכְבּוֹר</strong> (<em>baʿal ḥānān ben-ʿaḵḇôr</em>) — Baal-Hanan son of Akbor; the seventh king. The name <em>baʿal ḥānān</em> contains the Baal theophoric element — "Baal is gracious." This is the only king in the list with a name containing a Canaanite deity\'s name; it reflects the syncretistic religious environment of the Edomite monarchy. Akbor ("mouse") appears as a name in 2 Kgs 22:12 as the father of Achbor, a court official of Josiah — a name that persists across centuries in the Semitic onomasticon.</p>',
    "39": '<p><strong>וַיָּמָת בַּעַל חָנָן בֶּן-עַכְבּוֹר וַיִּמְלֹךְ תַּחְתָּיו הֲדַר</strong> — Hadad (eighth king, different spelling from v. 35\'s Hadad) succeeds Baal-Hanan. The final king\'s entry is uniquely expanded: <em>šēm ʿîrô pāʿû</em> (his city was Pau) and his wife\'s full genealogy: <em>mĕhêṭaḇʾēl bat-maṭrēḏ bat mê-zāhāḇ</em> (Mehetabel daughter of Matred, daughter of Mezahab). The wife\'s genealogy is unparalleled in the king-list — she is the only queen named in Edomite records. <em>Mê-zāhāḇ</em> (Me-Zahab — "waters of gold") is a suggestive name. The expanded entry for the final king may indicate that the king-list was compiled during or just after his reign, when more details were known about the current monarch.</p>',
    "40": '<p><strong>וְאֵלֶּה שְׁמוֹת אַלּוּפֵי עֵשָׂו לְמִשְׁפְּחֹתָם לִמְקֹמֹתָם</strong> — "these are the names of the chiefs of Esau, according to their clans and their places." The final chieftain-list returns to the <em>ʾallûp</em> structure (tribal chieftains, not dynastic kings). The two lists in ch. 36 — kings (vv. 31-39) and chieftains (vv. 40-43) — represent different periods or different organizational structures in Edomite society. The chieftain list here is organized by name + clan + region (<em>lišmōtām lĕmišpĕḥōtām lĕmĕqōmōtām</em>) — three organizational categories. <em>Timna</em> heads the final chieftain list — the same name as the Horite woman who bore Amalek (v. 12, 22) now appears as a territorial clan name.</p>',
    "41": '<p><strong>אַלּוּף אָהֳלִיבָמָה אַלּוּף אֵלָה אַלּוּף פִּינֹן</strong> — Oholibamah (the clan named for Esau\'s wife, now a territorial division), Elah (related to <em>ʾayil</em>, ram — a common Semitic place name; cf. Elath/Eilat on the Red Sea), Pinon (possibly <em>pûnôn</em>, the site identified with Punon in Transjordan, a copper-smelting site; cf. Num 33:42-43). The chieftains here are territorial entities, not individual persons — the "chief of Oholibamah" is the chief of the Oholibamah region, not Oholibamah herself. The woman\'s name has become a place name.</p>',
    "42": '<p><strong>אַלּוּף קְנַז אַלּוּף תֵּימָן אַלּוּף מִבְצָר</strong> — Kenaz (already a personal name in v. 11), Teman (already a clan name in v. 11; now also a territorial chief), Mibzar (<em>miḇṣār</em>, fortress/stronghold — a toponym meaning "fortification"; identified with Petra/Bozrah area in some traditions). The reuse of personal names (Kenaz, Teman) as both clan-names and territorial-chieftain designations reflects the standard ANE naming pattern where eponymous ancestors give their names to clans that give their names to territories.</p>',
    "43": '<p><strong>אַלּוּף מַגְדִּיאֵל אַלּוּף עִירָם</strong> — Magdiel ("prince of God/El" — a name containing the <em>ʾēl</em> theophoric) and Iram close the list. <strong>הוּא עֵשָׂו אֲבִי אֱדוֹם</strong> (<em>hûʾ ʿēśāw ʾăḇî ʾĔḏôm</em>) — "this is Esau, the father of Edom" — the closing formula; the fourth and final <em>hûʾ ʾĔḏôm</em> (he is Edom) identification in the chapter (vv. 1, 8, 19, 43). The four-fold equation Esau = Edom is the chapter\'s persistent refrain. The phrase <em>ʾăḇî ʾĔḏôm</em> (father of Edom) is the national-ancestor formula; it ends Esau\'s account exactly as 25:8 ended Abraham\'s account and 35:29 ended Isaac\'s — with a death notice in reverse: not death but the permanent identity statement of a nation-founding ancestor.</p>'
  },
  "37": {
    "1": '<p><strong>וַיֵּשֶׁב יַעֲקֹב בְּאֶרֶץ מְגוּרֵי אָבִיו בְּאֶרֶץ כְּנָעַן</strong> — "Jacob settled in the land of his father\'s sojournings, the land of Canaan." The verb <em>yāšaḇ</em> (to dwell, settle) — after the Edomite genealogy of ch. 36 (which showed Esau settled in his own territory), the narrator returns to Jacob with the same verb: <em>wayyēšeḇ yaʿăqōḇ</em>. But the contrast is deliberate: Esau <em>settled</em> in his own land (36:8: <em>wayyēšeḇ ʿēśāw bĕhar śēʿîr</em>); Jacob <em>settled</em> in the land of <em>sojournings</em> (<em>mĕgûrîm</em> = temporary resident-alien settlements, the noun from <em>gûr</em>, to sojourn). Esau has his own country; Jacob still sojourns as a covenant-stranger in Canaan.</p>',
    "2": '<p><strong>אֵלֶּה תֹּלְדוֹת יַעֲקֹב</strong> (<em>ʾēlleh tôlĕḏôt yaʿăqōḇ</em>) — "these are the generations of Jacob." The final <em>tôlĕḏôt</em> formula of Genesis; it opens the Joseph narrative. Structurally surprising: the toledoth of Jacob does not narrate Jacob\'s biography but introduces Joseph, his son. The pattern follows the earlier toledoth of Isaac (25:19ff.) which immediately shifted to Jacob and Esau — the toledoth formula consistently introduces the next generation\'s story. <em>Naʿar</em> (young man/lad) applied to Joseph at seventeen — the same word used for the servant/lad Ishmael (21:17-18), for the young men who accompanied Abraham (22:3, 5), for Jacob\'s young sons. At seventeen, Joseph is a <em>naʿar</em> — old enough to work the flocks but young enough to be subordinate. <strong>דִּבָּתָם רָעָה</strong> (<em>dibbāṯām rāʿāh</em>) — "their bad report" — <em>dibbāh</em> (report, ill report — specifically the kind of report that damages reputation; cf. Num 13:32 where the spies bring back an <em>dibbat hāʾāreṣ</em>, bad report of the land; Prov 10:18 where <em>môṣîʾ dibbāh</em>, one who spreads a bad report, is a fool). Whether Joseph was reporting accurately or slandering his brothers is not resolved; the narrator neither condemns nor defends him.</p>',
    "3": '<p><strong>וְיִשְׂרָאֵל אָהַב אֶת-יוֹסֵף מִכָּל-בָּנָיו</strong> — "Israel loved Joseph more than all his sons." The name <em>yiśrāʾēl</em> (Israel) is used here rather than Jacob — the narrator uses the covenant name for the patriarch when the narrative touches covenant-line matters. <em>ʾĀhaḇ</em> (the same love-verb used for Isaac\'s love of Esau, 25:28; for Jacob\'s love of Rachel, 29:18, 30) — the word for elective, particular love. <strong>בֶּן-זְקֻנִים</strong> (<em>ben-zĕqûnîm</em>) — "son of old age": the reason for the special love; the same phrase appears in 44:20 (Benjamin is also a <em>ben-zĕqûnîm</em>) — both the Rachel-sons are sons of Jacob\'s old age. <strong>כֻּתֹּנֶת פַּסִּים</strong> (<em>kuttōnet passîm</em>) — the famous garment: <em>kuttōnet</em> (tunic, undergarment worn close to the body — the same word as the "skin garments" of 3:21; the priestly tunic of Exod 28:4; 39:27); <em>passîm</em> (difficult: from <em>pas</em>, palm/sole, suggesting a garment reaching to the palms and soles, i.e., a long robe; or "striped"; or "ornamented"). In 2 Sam 13:18-19, the identical phrase <em>kuttōnet passîm</em> describes the garment worn by Tamar and other royal virgin daughters of David — a garment of high status. The robe marks Joseph as the favored heir, which is exactly what the brothers understand it to mean.</p>',
    "4": '<p><strong>וַיִּשְׂנְאוּ אֹתוֹ</strong> (<em>wayyiśnĕʾû ʾōtô</em>) — "they hated him." <em>Śānēʾ</em> (to hate — the opposite of <em>ʾāhaḇ</em>, to love; the same verb used for Leah, who was hated by Jacob, 29:31-33). The narrative sets up an explicit contrast: Israel loved Joseph (<em>ʾāhab</em>); the brothers hated him (<em>śānēʾ</em>). <strong>וְלֹא יָכְלוּ דַּבְּרוֹ לְשָׁלֹם</strong> (<em>wĕlōʾ yāḵĕlû dabĕrô lĕšālôm</em>) — "and they were not able to speak to him in peace/shalom." The idiom <em>dāḇar lĕšālôm</em> (to speak to someone\'s shalom) = to greet with shalom, to speak peacefully and well to someone. The brothers could not give Joseph even the standard greeting-word <em>šālôm</em>. The peace-word that binds covenant community (cf. 29:6: "is he in peace?" <em>hă-šālôm lô</em>?) was impossible between Joseph and his brothers — the relational covenant was already broken.</p>',
    "5": '<p><strong>וַיַּחֲלֹם יוֹסֵף חֲלוֹם</strong> (<em>wayyaḥălōm yôsēp ḥălôm</em>) — "Joseph dreamed a dream." The verb <em>ḥālam</em> (to dream) + noun <em>ḥălôm</em> (dream) — the cognate accusative construction emphasizes the dreaming: "he dreamed a dream." Dreams as vehicles of divine communication have appeared throughout Genesis (20:3, 6 — Abimelech; 28:12 — Jacob at Bethel; 31:10-11 — Jacob in Paddan-Aram). Joseph\'s dream-reception establishes him in the line of dream-receivers; his ability to interpret others\' dreams (chs. 40-41) develops from this gift. <em>Wayyaggēd lĕʾeḥāyw</em> (he told his brothers) — the telling of the dream is provocative; the text does not tell us Joseph told it naively or strategically; either way, the telling inflamed the situation.</p>',
    "6": '<p><strong>שִׁמְעוּ-נָא הַחֲלוֹם הַזֶּה אֲשֶׁר חָלָמְתִּי</strong> (<em>šimʿû-nāʾ haḥălôm hazzeh ʾăšer ḥālamtî</em>) — "please listen to this dream that I dreamed." The particle <em>nāʾ</em> (please, I pray — a softening particle used in polite or urgent requests; cf. 12:11; 18:3-4; 22:2) moderates the command; Joseph is asking his brothers to listen. The repetition of the word "dream" in vv. 5-10 — <em>ḥālam</em> and <em>ḥălôm</em> appearing eight times across six verses — saturates the passage with dream-language: this is the dream-story; everything else flows from what the dreams reveal.</p>',
    "7": '<p><strong>אֲלֻמָּתִי קָמָה וְגַם-נִצָּבָה</strong> (<em>ʾălummāṯî qāmāh wĕgam-niṣṣāḇāh</em>) — "my sheaf rose and stood upright." <em>ʾĂlummāh</em> (sheaf of grain — hapax; appears only here and Ps 126:6 where "carrying sheaves" is the image of joyful return from exile). The sheaf-imagery is harvest/agricultural: Joseph\'s sheaf rising above the brothers\' sheaves is the social reversal in agricultural terms. <em>Qāmāh</em> (rose up — Qal of <em>qûm</em>) + <em>niṣṣāḇāh</em> (stood upright — Niphal of <em>yāṣaḇ</em>, to stand firm/erect); the two verbs together express not just motion (rising) but permanence (standing erect). <em>Wattĕḥaweynāh ʾălummōtêḵem</em> (your sheaves bowed down) — <em>ḥāwāh</em> (to bow down — the same word used for Jacob bowing to Esau in 33:3 and for the patriarchal worship prostrations).</p>',
    "8": '<p><strong>הֲמָלֹךְ תִּמְלֹךְ עָלֵינוּ</strong> (<em>hămālōḵ timlōḵ ʿālênû</em>) — "will you indeed reign over us?" The emphatic infinitive absolute <em>māl ōḵ timlōḵ</em> — the doubling of the root (infinitive absolute + finite verb) expresses intense certainty or indignant disbelief: "are you really going to reign, reign over us?" <em>ʾIm-māšōl timšōl bānû</em> (or will you actually rule us?) — a second emphatic infinitive absolute, using <em>māšal</em> (to rule, have dominion — the same verb as 1:18 where the luminaries were to rule) alongside <em>mālaḵ</em> (to be king/reign). The two parallel rhetorical questions cover both the political verb of kingship (<em>mālaḵ</em>) and the practical verb of dominion (<em>māšal</em>) — the brothers read the dream\'s meaning accurately. <em>Wayyôsipû ʿôḏ śĕnōʾ ʾōtô</em> (they hated him even more) — the third occurrence of the hate-verb (vv. 4, 5, 8); each chapter-event escalates the brothers\' hatred.</p>',
    "9": '<p><strong>הַשֶּׁמֶשׁ וְהַיָּרֵחַ וְאַחַד עָשָׂר כּוֹכָבִים מִשְׁתַּחֲוִים לִי</strong> — "the sun, the moon, and eleven stars were bowing down to me." The cosmological dream replaces the agricultural: agricultural imagery (sheaves) was local; astronomical imagery (sun, moon, stars) is universal. Eleven stars = eleven brothers; the number is exact and immediately transparent. The sun and moon = father and mother; Jacob\'s interpretation in v. 10 assumes this. <em>Miśtaḥăwîm</em> (bowing down — Hishtaphel/Hitpael of <em>šāḥāh</em>) — the same prostration verb as in v. 7 and used throughout Genesis for worship before God and deference to superiors. The progression from brothers\' sheaves bowing (dream 1) to sun, moon, and eleven stars bowing (dream 2) escalates the scope: first the brothers; then the entire family.</p>',
    "10": '<p><strong>וַיִּגְעַר-בּוֹ אָבִיו</strong> (<em>wayyiḡʿar-bô ʾāḇîw</em>) — "his father rebuked him." <em>Gāʿar</em> (to rebuke, scold — a word for authoritative correction; used for YHWH rebuking the sea, Ps 106:9; for Jesus rebuking the wind, Mark 4:39/parallel). Jacob\'s rebuke is the appropriate paternal response to what sounds like presumptuous ambition. The question <em>hăḇôʾ nāḇôʾ ʾănî wĕʾimmĕḵā wĕʾaḥêḵā</em> (shall your mother and I and your brothers actually come?) — another emphatic infinitive absolute (<em>bāʾ nāḇôʾ</em>); and the problem: Rachel is already dead (35:19), making the "your mother" reference a narrative tension — either the dream refers to Bilhah (a surrogate mother; some rabbinic interpretation), or the detail is not pressed, or the narrative is not perfectly harmonized at this point. The MT does not resolve it; the narrator records Jacob\'s interpretation without correcting it.</p>',
    "11": '<p><strong>וַיְקַנְאוּ-בוֹ אֶחָיו</strong> (<em>wayyĕqannĕʾû-ḇô ʾeḥāyw</em>) — "his brothers were jealous of him." <em>Qinnēʾ</em> (Piel of <em>qānāʾ</em>, to be jealous, zealous — the root of <em>qinʾāh</em>, jealousy; God\'s jealousy for his people uses this root: Exod 20:5; 34:14; the same capacity that drives covenant-protectiveness in God drives destructive rivalry in humans). <em>Wĕʾāḇîw šāmar ʾet-haddāḇār</em> (but his father kept the matter in mind) — <em>šāmar</em> (to keep, observe, guard — used for keeping covenant, keeping the law; here: keeping the matter in mind, pondering it). The contrast: brothers <em>jealous</em>; father <em>keeps/ponders</em>. Luke 2:19 uses identical idiom for Mary pondering the shepherds\' words (<em>syneterein en tē kardia</em>) — the keeping-in-mind of a mystery not yet understood.</p>',
    "12": '<p><strong>וַיֵּלְכוּ אֶחָיו לִרְעוֹת אֶת-צֹאן אֲבִיהֶם בִּשְׁכֶם</strong> — "his brothers went to pasture their father\'s flock near Shechem." Shechem is the location of the Dinah/Simeon-Levi massacre (ch. 34); Jacob\'s sons have returned to the site of their earlier violence. The narrative moves forward without explicit connection to ch. 34, but the reader carries the knowledge that Shechem is a dangerous location in this family\'s history. The brothers\' presence there sets the stage for the mission Jacob gives Joseph.</p>',
    "13": '<p><strong>הִנֵּנִי</strong> (<em>hinnēnî</em>, here I am) — Joseph\'s response to his father\'s call. The covenant-readiness formula of Abraham (<em>hinnēnî</em> in 22:1, 7, 11) and Isaac (22:7) is now on Joseph\'s lips when his father calls him to go toward danger. Joseph does not know what awaits him; he simply makes himself available. The structural echo of Abraham\'s <em>hinnēnî</em> at the Akedah is not accidental: Joseph, like Isaac, will be sent on a journey by his father that involves figurative death and return. The word is one of the richest single words in Genesis for its structural weight.</p>',
    "14": '<p><strong>לֵךְ-נָא רְאֵה אֶת-שְׁלוֹם אַחֶיךָ וְאֶת-שְׁלוֹם הַצֹּאן</strong> — "go, please, see the peace/welfare of your brothers and the peace of the flock." The word <em>šālôm</em> (peace, well-being, wholeness) appears twice in Jacob\'s commission: check on your brothers\' <em>šālôm</em>; check on the flock\'s <em>šālôm</em>. The brothers who "could not speak his shalom" (v. 4) are the ones Joseph is sent to check on. The <em>šālôm</em>-word connects: Jacob sends Joseph to seek what the brothers refused to give. <em>Mēʿēmeq ḥeḇrôn</em> (from the Valley of Hebron) — Hebron is where Abraham was buried (25:9-10) and where Isaac lived (35:27); the patriarchal heartland sends Joseph out.</p>',
    "15": '<p><strong>וַיִּמְצָאֵהוּ אִישׁ</strong> (<em>wayyimṣāʾēhû ʾîš</em>) — "a man found him." The <em>ʾîš</em> (man) who appears to the wandering Joseph is unnamed and unexplained — he appears, gives directions, and disappears. The narrative economy of his appearance is striking: without this nameless man, Joseph would not have found his brothers at Dothan. Some read the <em>ʾîš</em> as an angelic figure (consistent with the pattern of unnamed divine messengers in Genesis); the text neither confirms nor denies. <em>Tōʿeh baśśāḏeh</em> (wandering in the field) — the verb <em>tāʿāh</em> (to wander, go astray — used for both physical and moral wandering; cf. Ps 119:176: "I have wandered like a lost sheep"; Isa 53:6: "we all have wandered"). Joseph is literally lost; the man\'s intervention is providential.</p>',
    "16": '<p><strong>אֶת-אַחַי אָנֹכִי מְבַקֵּשׁ</strong> (<em>ʾet-ʾaḥay ʾānōḵî mĕḇaqqēš</em>) — "my brothers I am seeking." The emphatic pronoun <em>ʾānōḵî</em> (I — the full first-person form used for emphasis) + the Piel participle <em>mĕḇaqqēš</em> (seeking, searching) — Joseph\'s search for his brothers is expressed with intensity. The Piel of <em>bāqaš</em> (to seek) is the word for intentional seeking: seeking God (Isa 55:6; Ps 27:8), seeking someone with purpose. Joseph\'s mission is to seek his brothers; the terrible irony is that he finds them and they destroy him.</p>',
    "17": '<p><strong>נָסְעוּ מִזֶּה</strong> (<em>nāsĕʿû mizzeh</em>, they moved on from here) — the brothers have moved from Shechem to Dothan. <em>Nāsaʿ</em> (to journey, set out, pull stakes — the verb of the Wilderness journeying: the Israelites "set out" from each campsite in Num 33). <em>Dōṯānāh</em> (Dothan) — a real location north of Shechem (modern Tell Dothan); identified with Dothan in the plain; its remoteness from Jacob at Hebron gives the brothers time and isolation for what follows. <em>Wayyāḇōʾ yôsēp ʾaḥărê ʾeḥāyw</em> (Joseph went after his brothers) — <em>ʾaḥărê</em> (after, behind) — Joseph follows his brothers; the word subtly echoes the narrative theme of following versus leading that the dreams have set up.</p>',
    "18": '<p><strong>וַיִּרְאוּ אֹתוֹ מֵרָחֹק</strong> (<em>wayyirʾû ʾōtô mērāḥōq</em>) — "they saw him from a distance." <em>Rāḥōq</em> (far off, at a distance) — the brothers see Joseph before he reaches them; the distance gives them time to conspire. <em>Wĕyitnakkĕlû ʾōtô</em> (they conspired against him) — <em>nākal</em> (Hitpael, to conspire, plot with deceit against someone — a rare and strong word for treacherous plotting; cf. Ps 105:25 where Egypt "conspired" against Israel; Mal 1:14 where it is used for deceptive sacrifice). The plotting is premeditated and deceitful; the Hitpael form expresses the reflexive-intensive: they strategized with each other against him.</p>',
    "19": '<p><strong>הִנֵּה בַּעַל הַחֲלֹמוֹת הַלָּזֶה בָּא</strong> (<em>hinnēh baʿal haḥălōmôt hallāzeh bāʾ</em>) — "here comes this master of dreams!" <em>Baʿal haḥălōmôt</em> (master/owner of the dreams — <em>baʿal</em> = lord, master, owner, husband; the term of possession or mastery). The phrase is mocking: "this dream-master" — a derisive title that simultaneously acknowledges the power of the dreams (they are real dreams) and expresses contempt for the dreamer. <em>Hallāzeh</em> (this one, this person here — a demonstrative pronoun with a distancing, sometimes contemptuous force: "this one there"). The sarcasm is exact Hebrew: <em>baʿal haḥălōmôt hallāzeh</em> = "this dream-lord here."</p>',
    "20": '<p><strong>וְנִרְאֶה מַה-יִּהְיוּ חֲלֹמֹתָיו</strong> (<em>wĕnirʾeh mah-yihyû ḥălōmōṯāyw</em>) — "and we shall see what becomes of his dreams." The bitter irony of the verse: the brothers\' plan to kill the dreamer and eliminate the dreams will in fact set the dreams\' fulfillment in motion. The cistern they throw him into will lead to Egypt; Egypt will lead to Pharaoh\'s dreams; Pharaoh\'s dreams will lead to Joseph\'s rule; Joseph\'s rule will bring the brothers to bow. <em>Ûnirʾeh</em> (and we shall see) — the Niphal cohortative "we will see" — the brothers intend to see the dreams fail; what they will see, in ch. 42-44, is the dreams come true. The narrative\'s deepest irony runs through this single clause.</p>',
    "21": '<p><strong>וַיִּשְׁמַע רְאוּבֵן וַיַּצִּלֵהוּ מִיָּדָם</strong> (<em>wayyišmaʿ rĕʾûḇēn wayyaṣṣîlēhû miyyāḏām</em>) — "Reuben heard and rescued him from their hands." <em>Šāmaʿ</em> (to hear, listen — the foundational verb of response and covenant-loyalty; cf. the <em>Šĕmaʿ</em>: "Hear, O Israel"). Reuben\'s hearing leads to intervention: <em>hiṣṣîl</em> (Hiphil of <em>nāṣal</em>, to rescue, deliver — the same word used for God\'s deliverance: Exod 3:8; Ps 50:15). Reuben uses the rescue-word that belongs to divine action. <em>ʾAl-tišpĕḵû-dām</em> (do not shed blood) — <em>šāpaḵ dām</em> (to shed blood) — the same blood-shedding language of Gen 9:6 (the Noahic covenant against bloodshed) and of the later Mosaic law against murder. Reuben invokes the foundational prohibition.</p>',
    "22": '<p><strong>לְמַעַן הַצִּיל אֹתוֹ מִיָּדָם לַהֲשִׁיבוֹ אֶל-אָבִיו</strong> (<em>lĕmaʿan haṣṣîl ʾōtô miyyāḏām lăhăšîḇô ʾel-ʾāḇîw</em>) — "to rescue him from their hands and return him to his father." The narrator reveals Reuben\'s interior motive — an unusual instance of explicit motive-disclosure in Genesis narrative (cf. the same transparency in 37:33 when Jacob interprets the robe, and in 31:31 when Jacob explains his flight). Reuben\'s plan: use the cistern as a delaying tactic; when the others\' attention is elsewhere, retrieve Joseph and return him to Jacob. The plan fails because Reuben is absent when the Ishmaelite traders arrive (v. 29). The narrative does not tell us where Reuben went; his absence at the crucial moment is unexplained.</p>',
    "23": '<p><strong>וַיַּפְשִׁיטוּ אֶת-יוֹסֵף אֶת-כֻּתָּנְתּוֹ אֶת-כְּתֹנֶת הַפַּסִּים</strong> — "they stripped Joseph of his robe, the ornamented robe he was wearing." <em>Pāšaṭ</em> (Hiphil: to strip, take off clothing from someone — the word used for removing priestly garments in Lev 6:4; Num 20:26; here it is violent removal of the status-garment). The repetition: "his robe" + "the ornamented robe" — the double identification of the ketonet passim at the moment of its removal emphasizes what is being taken: not just a garment but the father\'s love, the heir-sign, the status marker. The robe that Jacob made for Joseph is stripped off; the garment will be soaked in blood and used to deceive Jacob (v. 31-33) — the robe becomes the instrument of the deception of the father by the sons, mirroring Jacob\'s deception of Isaac with the goatskin.</p>',
    "24": '<p><strong>וַיַּשְׁלִכוּ אֹתוֹ הַבֹּרָה</strong> (<em>wayyašlîḵû ʾōtô habbōrāh</em>) — "they threw him into the pit." <em>Šālaḵ</em> (to throw, cast — the violent disposal verb; used for the discarding of the golden calf into water, Exod 32:24; for the casting of Jonah into the sea, Jonah 1:15; for judgment-casting in Jer 22:19). <em>Bôr</em> (pit, cistern — the word covers dry storage cisterns, wells, and metaphorically the underworld/Sheol; Ps 28:1; 30:4 [Heb 30:4]; Isa 14:15; 38:18 use <em>bôr</em> for the realm of death). Joseph enters a <em>bôr</em> — a death-space; the narrator adds: <em>wĕhabbôr rēq ʾên bô māyim</em> (the pit was empty; there was no water in it). The absence of water (<em>ʾên māyim</em>) prevents immediate death by drowning but leaves Joseph without resources — alive but helpless. The emptiness of the pit is the condition of his survival.</p>',
    "25": '<p><strong>וַיֵּשְׁבוּ לֶאֱכָל-לֶחֶם</strong> (<em>wayyēšĕḇû lĕʾĕḵol-leḥem</em>) — "they sat down to eat bread." The shocking juxtaposition: Joseph is in the pit; the brothers sit to eat. The eating-while-the-other-suffers will be remembered in the later narrative — Judah\'s speech to Joseph in 44:18-34 does not mention the pit, but the brothers\' guilty memory of "when they saw the distress of his soul, when he pleaded with us, and we did not listen" (42:21) suggests the eating scene was remembered as the moment of hardness. <em>ʾŌrĕḥat yišmĕʿēʾlîm</em> (a caravan of Ishmaelites) — <em>ʾōrāḥāh</em> (caravan — the camel-train of long-distance traders; Ps 68:10 uses the word for the "company" of God\'s people). The Ishmaelites are from Gilead, carrying <em>nĕḵōʾt ûṣĕrî wālōṭ</em> (spices, balm, and myrrh) — three aromatic trade goods; the balm of Gilead (<em>ṣĕrî</em>) appears in Jer 8:22; 46:11 as the therapeutic product of the Gilead region. The trading route from Gilead to Egypt is historically attested.</p>',
    "26": '<p><strong>מַה-בֶּצַע כִּי נַהֲרֹג אֶת-אָחִינוּ</strong> (<em>mah-beṣaʿ kî nahărōg ʾet-ʾāḥînû</em>) — "what profit is there if we kill our brother?" <em>Beṣaʿ</em> (gain, profit — frequently with the connotation of dishonest or unjust profit; cf. Exod 18:21; 1 Sam 8:3; Isa 56:11; Jer 6:13 where <em>bōṣēaʿ beṣaʿ</em>, "greedy for gain," characterizes the corrupt). Judah\'s argument is pragmatic-economic, not moral: the question is not "is it wrong to kill Joseph?" but "what do we gain?" <em>Wĕkissînû ʾet-dāmô</em> (and we cover up his blood) — <em>kāsāh dām</em> (to cover blood) — the idiom for concealing a murder; cf. Job 16:18 where Job asks the earth not to cover his blood (i.e., not to conceal the injustice done to him). Judah\'s argument: death is unproductive and creates a bloodguilt that must be hidden.</p>',
    "27": '<p><strong>כִּי-אָחִינוּ בְשָׂרֵנוּ הוּא</strong> (<em>kî-ʾāḥînû ḇĕśārēnû hûʾ</em>) — "for he is our brother, our flesh." <em>Bāśār</em> (flesh — the word for kinship solidarity: "bone of my bone and flesh of my flesh" [2:23]; the kinship-solidarity principle that Judah invokes: you do not harm your own flesh). The argument: sell him rather than kill him — he remains alive, we gain silver, and we have not violated the flesh-solidarity obligation. <em>Wayyišmĕʿû ʾeḥāyw</em> (his brothers listened) — the verb <em>šāmaʿ</em> (to hear, listen, obey); the brothers consent to Judah\'s proposal. The same verb that opened Reuben\'s intervention (v. 21: "Reuben heard") closes Judah\'s: both brothers use the hearing-verb, but with very different outcomes.</p>',
    "28": '<p><strong>אַנְשֵׁי מִדְיָן סֹחֲרִים</strong> (<em>ʾanšê miḏyān sōḥărîm</em>) — "Midianite traders." The buyers are variously called Ishmaelites (vv. 25, 27) and Midianites (v. 28) and Medanites (v. 36). The three names likely reflect the overlapping tribal confederacies of the Transjordan: Ishmaelites and Midianites were closely related (both descended from Abraham — through Hagar and Keturah respectively, 25:2; 16:15) and shared the same trade routes. The narrative uses them interchangeably as desert traders. <strong>בְּעֶשְׂרִים כָּסֶף</strong> (<em>bĕʿeśrîm kāsep</em>, for twenty pieces of silver) — the price; Lev 27:5 sets the redemption price for persons aged 5-20 at twenty shekels — a standard slave-price for a young person in ANE contexts. The silver that Joseph\'s brothers receive for him will reappear in the narrative: 42:25-35 (brothers\' silver returned in their sacks); 44:2 (Joseph\'s silver cup planted in Benjamin\'s sack). The silver motif runs through the Joseph story.</p>',
    "29": '<p><strong>וַיָּשָׁב רְאוּבֵן אֶל-הַבּוֹר</strong> (<em>wayyāšāḇ rĕʾûḇēn ʾel-habbôr</em>) — "Reuben returned to the pit." The verb <em>šûḇ</em> (to return) — Reuben comes back to execute his rescue plan; he finds Joseph gone. <em>Wayyiqraʿ ʾet-bĕḡāḏāyw</em> (he tore his clothes) — the garment-tearing of mourning; the same gesture Jacob will make in v. 34. Reuben tears his clothes at the empty pit just as Jacob will tear his clothes at the blood-stained robe. Both mournings are real grief; both are also responses to deception. Reuben\'s grief is the grief of a failed rescuer; the narrative records it without condemnation but also without full absolution — Reuben did not prevent the sale.</p>',
    "30": '<p><strong>הַיֶּלֶד אֵינֶנּוּ וַאֲנִי אָנָה אֲנִי-בָא</strong> (<em>hayyeleḏ ʾênennû waʾănî ʾānāh ʾănî-ḇāʾ</em>) — "the boy is gone! Where can I go?" <em>Yeleḏ</em> (child, boy — a more intimate word than <em>naʿar</em>; used for newborns and young children; Reuben calls Joseph a child, the vulnerable one). <em>ʾĀnāh ʾănî-ḇāʾ</em> (where can I go?) — the question of desperate accountability: "I, where am I to go?" — meaning "I am responsible; there is nowhere to hide from this failure; how do I face my father?" The question anticipates Jacob\'s grief: Jacob will also have "nowhere to go" in his mourning (v. 35: he refuses to be comforted). The two questions — Reuben\'s "where do I go?" and Jacob\'s "I will go to Sheol" — frame the family\'s devastation.</p>',
    "31": '<p><strong>וַיִּשְׁחֲטוּ שְׂעִיר עִזִּים</strong> (<em>wayyišḥăṭû śĕʿîr ʿizzîm</em>) — "they slaughtered a male goat." <em>Šāḥaṭ</em> (to slaughter — the technical verb for ritual slaughter of animals; used for sacrificial killing throughout Leviticus and Numbers). The brothers use the slaughter-verb — the same action Joseph\'s sons Ephraim and Manasseh will perform in Egypt. A male goat (<em>śĕʿîr ʿizzîm</em>) — <em>śĕʿîr</em> (hairy goat; the word is identical to the territory Seir, Esau\'s land; and to Esau himself who was hairy). Jacob was deceived by his sons Simeon and Levi (and the Dinah-revenge) into eating goat in his old age; now he will be deceived by the goat\'s blood into believing Joseph is dead. The family\'s goat-deception motif runs from 27:9 (goat for the Esau-blessing deception) to here.</p>',
    "32": '<p><strong>שְׁלַח אֶת-כְּתֹנֶת הַפַּסִּים</strong> (<em>šālaḥ ʾet-kĕtōnet happasîm</em>) — "they sent the ornamented robe." <em>Šālaḥ</em> (to send — the pivotal action-verb of the narrative: Jacob sent Joseph [v. 13]; God will send Joseph to Egypt ahead of the family [45:5, 7-9]; now the brothers "send" the bloody robe). <em>Hakkēr-nāʾ</em> (please examine/recognize) — <em>nākar</em> (Hiphil: to recognize, examine closely — Tamar will use the same word in 38:25-26 when she sends Judah\'s identifying objects: "please recognize whose these are"). <em>Hakkēr-nāʾ</em> is technically a request; the brothers\' usage is a demand disguised as a request. The robe that Jacob gave Joseph now comes back covered in blood; the recognition is forced on Jacob.</p>',
    "33": '<p><strong>וַיַּכִּרָהּ</strong> (<em>wayyakkirāh</em>) — "he recognized it." The same verb as v. 32 (<em>nākar</em>); Jacob performs the recognition the brothers demanded. <em>Kĕtōnet bĕnî ḥayyāh rāʿāh ʾăḵālatĕhû</em> (my son\'s robe! A ferocious animal has devoured him) — Jacob\'s interpretation is exactly what the brothers intended him to conclude. <em>Ṭārōp ṭōrap yôsēp</em> (Joseph has surely been torn to pieces) — emphatic infinitive absolute: <em>ṭārap</em> (to tear prey, as a predator tears its victim — used for the tearing of the shepherd\'s flock in 31:39 where Jacob argued he bore the losses of torn animals; now it is turned against Jacob\'s own son). The narrative has Jacob use the same <em>ṭerepāh</em> vocabulary he used in his legal defense of Laban: there he claimed torn animals were his responsibility; here his son is the one said to be torn.</p>',
    "34": '<p><strong>וַיִּקְרַע יַעֲקֹב שִׂמְלֹתָיו וַיָּשֶׂם שַׂק בְּמָתְנָיו</strong> — "Jacob tore his garments and put on sackcloth on his waist." <em>Qāraʿ</em> (to tear — the standard mourning gesture; the garment torn at the neck or chest; performed for death of a first-degree relative: 2 Sam 1:11-12; 13:31; Job 1:20). <em>Śaq</em> (sackcloth — the coarse material of mourning and fasting; cf. 1 Kgs 21:27; Joel 1:8; Isa 58:5; Jon 3:5-6). <em>Wayyitʾabbēl ʿal-bĕnô yāmîm rabbîm</em> (he mourned for his son many days) — <em>ʾāḇal</em> (to mourn — the formal mourning posture); <em>yāmîm rabbîm</em> (many days — an indefinite period of extended mourning; 22 years is the implied duration, since Joseph is 30 when he stands before Pharaoh [41:46] and was 17 when sold).</p>',
    "35": '<p><strong>וַיְמָאֵן לְהִתְנַחֵם</strong> (<em>waymāʾēn lĕhitnáḥem</em>) — "he refused to be comforted." <em>Māʾēn</em> (Piel: to refuse, reject — the same verb for Pharaoh refusing to let Israel go, Exod 7:14; 8:2; for the refusal of covenant terms). Jacob refuses consolation: not merely unable to be comforted but actively refusing it. <em>Hitnáḥem</em> (Hitpael of <em>nāḥam</em>: to be comforted, to console oneself — the reflexive of the comfort-root; Ps 119:52 uses the same Hitpael for "I comfort myself with your ordinances"). <strong>כִּי-אֵרֵד אֶל-בְּנִי אָבֵל שְׁאֹלָה</strong> (for I will go down to Sheol mourning for my son) — <em>šĕʾôl</em> (Sheol — the underworld, the realm of the dead in OT cosmology; a dark, inert place of no return; cf. Ps 6:5; 30:3; Eccl 9:10). Jacob will mourn until he joins Joseph in death: the mourning and the grave are inseparable for him. The tragic irony: Joseph is alive. Jacob mourns for 22 years for a living son.</p>',
    "36": '<p><strong>וְהַמְּדָנִים מָכְרוּ אֹתוֹ אֶל-מִצְרָיִם</strong> (<em>wĕhammĕḏānîm māḵrû ʾōtô ʾel-miṣrāyim</em>) — "the Medanites sold him into Egypt." <em>Mĕḏānîm</em> (Medanites — yet a third name for the traders, from Medan son of Abraham and Keturah, 25:2) — the third name-variant in four verses (Ishmaelites, Midianites, Medanites) reflects the fluid tribal identity of the region; the narrative\' s interchangeable use of these names is consistent with the actual kinship connections between these groups. <strong>לְפוֹטִיפַר סְרִיס פַּרְעֹה</strong> (<em>lĕpôṭîpar sĕrîs parʿōh</em>) — "to Potiphar, an official of Pharaoh." <em>Sārîs</em> (official, courtier — from Akkadian <em>ša-rēši</em>, "of the head/of the court"; can mean eunuch but here likely means royal official, given Potiphar\'s married status in ch. 39). <em>Śar haṭṭabbāḥîm</em> (captain of the guard) — literally "chief of the slaughterers/executioners"; <em>ṭabbāḥ</em> (butcher, cook, executioner/guard — a royal official with judicial and military functions in the ANE court; the Akkadian cognate <em>ṭabbāḥu</em> designates a similar court functionary). Joseph enters the most powerful empire of the ancient world as a slave — the lowest possible position — in the service of a man whose title is "chief of executioners." The descent from favorite son to condemned slave is complete.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-original', 'genesis', existing)
    print('Genesis 36-37 mkt-original written.')

if __name__ == '__main__':
    main()
